// // This D latch will set the output to 1 when the enable signal is low
module top_module (
    input clk,
    input reset,
    input d,
    input enable,
    output q );reg q_reg;

    always @(posedge clk) begin
        if (reset)
            q_reg <= 1'b0;
        else if (enable)
            q_reg <= d;
    end

    assign q = q_reg;

endmodule
